func solve(nums []int64) int64 {
	var totalSum int64 = 0
	n := len(nums)

	for i := 0; i < n-1; i++ {
		// If nums[i] > nums[i+1], we have a violation.
		// We need to increase nums[i+1] relative to nums[i] by at least nums[i] - nums[i+1].
		// The minimum total sum of x's required is the sum of all such positive drops.
		if nums[i] > nums[i+1] {
			totalSum += nums[i] - nums[i+1]
		}
	}

	return totalSum
}
